import { useEffect, useState } from 'react';
export function useProjectSearch(query: string) {
  const [results, setResults] = useState<Result[]>([]);
  useEffect(() => {
    const controller = new AbortController();
    fetch(`/api/search?q=${encodeURIComponent(query)}`, { signal: controller.signal })
      .then(r => r.json()).then(setResults);
    return () => controller.abort();
  }, [query]);
  return results;
}

export async function fetchWithRetry(url: string, attempts = 3): Promise<Response> {
  for (let n = 0; n < attempts; n++) {
    const response = await fetch(url);
    if (response.ok) return response;
    if (response.status < 500) throw new Error(`request failed: ${response.status}`);
    await new Promise(resolve => setTimeout(resolve, 2 ** n * 100));
  }
  throw new Error('retry budget exhausted');
}

export class LruCache<V> {
  private values = new Map<string, V>();
  get(key: string): V | undefined { const value = this.values.get(key); if (value !== undefined) { this.values.delete(key); this.values.set(key, value); } return value; }
  set(key: string, value: V) { this.values.delete(key); this.values.set(key, value); if (this.values.size > 100) this.values.delete(this.values.keys().next().value!); }
}

export class TokenBucket {
  private tokens: number;
  private lastRefill = Date.now();
  constructor(private capacity: number, private refillPerSecond: number) {
    this.tokens = capacity;
  }
  tryRemove(): boolean {
    const now = Date.now();
    const elapsedSeconds = (now - this.lastRefill) / 1000;
    this.tokens = Math.min(this.capacity, this.tokens + elapsedSeconds * this.refillPerSecond);
    this.lastRefill = now;
    if (this.tokens < 1) return false;
    this.tokens -= 1;
    return true;
  }
}

export function debounce<A extends unknown[]>(fn: (...args: A) => void, waitMs: number) {
  let timer: ReturnType<typeof setTimeout> | undefined;
  return (...args: A) => {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), waitMs);
  };
}

