import asyncio
async def request_with_backoff(client, url, attempts=4):
    for attempt in range(attempts):
        try:
            return await client.get(url)
        except TimeoutError:
            if attempt + 1 == attempts:
                raise
            await asyncio.sleep(0.1 * (2 ** attempt))

from math import sqrt
def cosine_similarity(left, right):
    dot = sum(a * b for a, b in zip(left, right))
    left_norm = sqrt(sum(a * a for a in left))
    right_norm = sqrt(sum(b * b for b in right))
    if not left_norm or not right_norm:
        raise ValueError('zero vector')
    return dot / (left_norm * right_norm)

def extract_unique_span(source, anchor, before, after):
    if source.count(anchor) != 1:
        raise ValueError('anchor must occur exactly once')
    lines = source.splitlines()
    line = next(i for i, value in enumerate(lines) if anchor in value)
    return '\n'.join(lines[max(0, line-before):line+after+1])

import time
from functools import wraps

def ttl_cache(seconds=300):
    def decorator(fn):
        entries = {}
        @wraps(fn)
        def wrapper(*args):
            now = time.monotonic()
            hit = entries.get(args)
            if hit and now - hit[1] < seconds:
                return hit[0]
            value = fn(*args)
            entries[args] = (value, now)
            return value
        return wrapper
    return decorator

