class JsonFormatter(logging.Formatter):
    def format(self, record):
        payload = {'level': record.levelname, 'logger': record.name, 'message': record.getMessage()}
        if record.exc_info:
            payload['exc'] = self.formatException(record.exc_info)
        return json.dumps(payload)

def setup_logging():
    handler = logging.StreamHandler(sys.stdout)
    handler.setFormatter(JsonFormatter())
    logging.basicConfig(level=os.environ.get('LOG_LEVEL', 'INFO'), handlers=[handler])

import re
def markdown_toc(text):
    toc = []
    for line in text.splitlines():
        match = re.match(r'(#{1,6})\s+(.*)', line)
        if match:
            depth = len(match.group(1)) - 1
            toc.append('  ' * depth + '- ' + match.group(2))
    return '\n'.join(toc)

pub fn batches<T>(items: &[T], size: usize) -> impl Iterator<Item = &[T]> {
