typedef struct {
    double values[RING_CAPACITY];
    size_t head;
    size_t count;
} ring_buffer;

void ring_push(ring_buffer *rb, double value) {
    size_t tail = (rb->head + rb->count) % RING_CAPACITY;
    rb->values[tail] = value;
    if (rb->count < RING_CAPACITY) {
        rb->count++;
    } else {
        rb->head = (rb->head + 1) % RING_CAPACITY; /* overwrite oldest */
    }
}

static volatile sig_atomic_t stop_requested = 0;

static void handle_sigint(int signo) {
    (void)signo;
    stop_requested = 1;
}

int install_signal_handlers(void) {
    struct sigaction sa = {0};
    sa.sa_handler = handle_sigint;
    sigemptyset(&sa.sa_mask);
    if (sigaction(SIGINT, &sa, NULL) == -1) return -1;
    if (sigaction(SIGTERM, &sa, NULL) == -1) return -1;
    return 0;
}

void mat_mul(const float *a, const float *b, float *out, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            float sum = 0.0f;
            for (int k = 0; k < n; k++) {
                sum += a[i * n + k] * b[k * n + j];
            }
            out[i * n + j] = sum;
        }
    }
}

